#include <bits/stdc++.h>
using namespace std;
const int N=1003,mod=1e4;
int n,m,f[N][N],s[N][N];
int main(){
    scanf("%d%d",&n,&m);
    f[1][0]=1;
    for(int j=0;j<=m;j++)
    	s[1][j]=1;
    for(int i=2;i<=n;i++)
        for(int j=0;j<=m;j++){
            /*for(int k=j-min(i,j+1)+1;k<=j;k++)
                f[i][j]+=f[i-1][k];*/
            if(j<j-min(i,j+1))
            	f[i][j]=s[i-1][j];
            else
            	f[i][j]=(s[i-1][j]-s[i-1][j-min(i,j+1)]+mod)%mod; 
        	s[i][j]=(f[i][j]+s[i][j-1])%mod;
		}
    printf("%d",f[n][m]);
    return 0;
}
